def normalize_resume(payload):
    email = payload['email'].strip()
    if '@' not in email:
        raise ValueError("email field missing '@' separator")
    return {'email': email.lower()}

def run(payload):
    normalized = normalize_resume(payload)
    return {'normalized': normalized, 'warnings': []}

def test_warn_on_bad_email():
    payload = {'email': 'invalid.example.com'}
    result = run(payload)
    assert result['warnings'] == ['invalid email']
